  "#60a5fa",
  "#5badf5",
  "#56b5f0",
  "#51bdeb",
  "#4cc5e6",
  "#47cde1",
  "#42d5dc",
  "#3dd8d2",
  "#38d9c4",
  "#34d399",
  "#45d48f",
  "#56d585",
  "#67d67b",
  "#78d771",
  "#89d867",
];

function formatVolume(value: number): string {
  if (value >= 1_000_000) return `${(value / 1_000_000).toFixed(1)}M`;
  if (value >= 1_000) return `${(value / 1_000).toFixed(1)}K`;
  return value.toFixed(0);
}

