      <div className="space-y-2 mt-4">
        {Array.from({ length: 15 }).map((_, i) => (
          <div key={i} className="flex items-center gap-3">
            <Skeleton className="h-4 w-28 bg-zinc-800" />
            <Skeleton
              className="h-6 bg-zinc-800"
              style={{ width: `${95 - i * 5}%` }}
            />
          </div>
        ))}
      </div>
    </div>
  );
}

