    return map;
  }, [data]);

  // Reversed for Recharts horizontal bar (bottom-to-top rendering)
  const chartData = useMemo(() => [...data].reverse(), [data]);

  if (loading && data.length === 0) {
    return <LoadingSkeleton />;
