import React from "react";

interface TooltipPayload {
  name: string;
  image: string;
  trade_volume_24h_btc: number;
  trust_score: number;
  trust_score_rank: number;
  country: string | null;
  year_established: number | null;
}

export function CustomTooltip({ active, payload }: any) {
  if (!active || !payload || !payload.length) return null;

  const d: TooltipPayload = payload[0].payload;
  const vol = d.trade_volume_24h_btc;

  const trustColor =
    d.trust_score >= 8
      ? "text-emerald-400"
      : d.trust_score >= 5
      ? "text-yellow-400"
      : "text-red-400";

  return (
    <div className="bg-zinc-900 border border-zinc-700 p-3 shadow-xl min-w-[220px]">
      <div className="flex items-center gap-2 mb-2">
        <img
          src={d.image}
          alt={d.name}
          className="w-5 h-5"
          onError={(e) => {
            (e.target as HTMLImageElement).style.display = "none";
          }}
        />
        <span className="text-zinc-100 font-semibold text-sm">{d.name}</span>
      </div>
      <div className="space-y-1 text-xs">
        <div className="flex justify-between gap-4">
          <span className="text-zinc-400">24h Volume</span>
          <span className="text-zinc-100 font-mono font-semibold">
            {vol.toLocaleString("en-US", {
              minimumFractionDigits: 2,
              maximumFractionDigits: 2,
            })}{" "}
            BTC
          </span>
        </div>
        <div className="flex justify-between gap-4">
          <span className="text-zinc-400">Trust Score</span>
          <span className={`font-mono font-semibold ${trustColor}`}>
            {d.trust_score}/10
          </span>
        </div>
        <div className="flex justify-between gap-4">
          <span className="text-zinc-400">Rank</span>
          <span className="text-zinc-300 font-mono">#{d.trust_score_rank}</span>
        </div>
        {d.country && (
          <div className="flex justify-between gap-4">
            <span className="text-zinc-400">Country</span>
            <span className="text-zinc-300">{d.country}</span>
          </div>
        )}
        {d.year_established && (
          <div className="flex justify-between gap-4">
            <span className="text-zinc-400">Est.</span>
            <span className="text-zinc-300 font-mono">{d.year_established}</span>
          </div>
        )}
      </div>
    </div>
  );
}

