import React from "react";

interface TickProps {
  x: number;
  y: number;
  payload: { value: string };
  exchangeImages: Record<string, string>;
}

export function CustomYAxisTick({ x, y, payload, exchangeImages }: TickProps) {
  const name = payload.value;
  const imgSrc = exchangeImages[name];
  const displayName = name.length > 14 ? name.slice(0, 13) + "…" : name;

  return (
    <g transform={`translate(${x},${y})`}>
      {imgSrc && (
        <image
          href={imgSrc}
          x={-145}
          y={-8}
          width={16}
          height={16}
        />
      )}
      <text
        x={-125}
        y={0}
        dy={4}
        textAnchor="start"
        fill="#d4d4d8"
        fontSize={11}
        fontFamily="monospace"
      >
        {displayName}
      </text>
    </g>
  );
}

